import React, { useState } from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend } from 'recharts';

function App() {
  const [role, setRole] = useState('Admin');
  const [items, setItems] = useState([
    { id: 1, name: 'Kopi Bubuk', stock: 8, minStock: 10, barcode: '888111' },
    { id: 2, name: 'Gula Pasir', stock: 30, minStock: 15, barcode: '888222' },
    { id: 3, name: 'Teh Celup', stock: 100, minStock: 20, barcode: '888333' },
    { id: 4, name: 'Susu Cair', stock: 25, minStock: 12, barcode: '888444' },
    { id: 5, name: 'Roti Tawar', stock: 50, minStock: 10, barcode: '888555' },
    { id: 6, name: 'Minuman Soda', stock: 15, minStock: 20, barcode: '888666' },
    { id: 7, name: 'Biskuit Coklat', stock: 40, minStock: 8, barcode: '888777' },
    { id: 8, name: 'Mie Instan', stock: 60, minStock: 15, barcode: '888888' },
    { id: 9, name: 'Kacang Tanah', stock: 22, minStock: 10, barcode: '888999' },
    { id: 10, name: 'Coklat Batang', stock: 35, minStock: 5, barcode: '888000' }
  ]);
  const [rewards, setRewards] = useState(0);
  const [history, setHistory] = useState([]);
  const [historyRewards, setHistoryRewards] = useState([]);
  const [selectedReward, setSelectedReward] = useState('');
  const [rewardQuantity, setRewardQuantity] = useState('');
  const [rewardType, setRewardType] = useState('Masuk');
  const [rewardsItems, setRewardsItems] = useState([
    { name: 'Tas', stock: 2 },
    { name: 'Topi', stock: 1 },
    { name: 'Botol Minum', stock: 0 },
    { name: 'Kaos', stock: 3 }
  ]);
  const [selectedItem, setSelectedItem] = useState('');
  const [quantity, setQuantity] = useState('');
  const [type, setType] = useState('Masuk');

  const lowStockItems = items.filter(item => item.stock <= item.minStock);

  const handleTransaction = () => {
    if (!selectedItem || !quantity) return;
    const item = items.find(i => i.name === selectedItem);
    if (!item) return;
    const qty = parseInt(quantity);
    let newStock = item.stock;
    if (type === 'Masuk') {
      newStock += qty;
    } else {
      newStock -= qty;
    }
    setItems(items.map(i => i.id === item.id ? { ...i, stock: newStock } : i));
    setHistory([...history, { item: selectedItem, type, quantity: qty, date: new Date().toLocaleString() }]);
    setSelectedItem('');
    setQuantity('');
  };

  const scanBarcode = () => {
    setSelectedItem('Gula Pasir');
  };

  const redeemReward = () => {
    if (!selectedReward) {
      alert('Pilih hadiah terlebih dahulu!');
      return;
    }
    const reward = rewardsItems.find(r => r.name === selectedReward);
    if (!reward || reward.stock <= 0) {
      alert('Hadiah tidak tersedia!');
      return;
    }
    setRewardsItems(rewardsItems.map(r => r.name === selectedReward ? { ...r, stock: r.stock - 1 } : r));
    setHistoryRewards([...historyRewards, { type: 'Keluar', name: selectedReward, quantity: 1, date: new Date().toLocaleString() }]);
    alert(`Hadiah ${selectedReward} dipilih!`);
    setSelectedReward('');
  };

  return (
    <div style={{ 
      padding: '20px', 
      fontFamily: 'Arial, sans-serif', 
      background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)', 
      minHeight: '100vh', 
      color: '#fff' 
    }}>
      <div style={{ 
        maxWidth: '1200px', 
        margin: '0 auto', 
        background: 'rgba(255, 255, 255, 0.1)', 
        borderRadius: '15px', 
        padding: '30px', 
        boxShadow: '0 8px 32px rgba(0, 0, 0, 0.3)' 
      }}>
        <h1 style={{ textAlign: 'center', marginBottom: '30px', fontSize: '2.5em', textShadow: '2px 2px 4px rgba(0,0,0,0.5)' }}>Stokin v2.0 - Sistem Manajemen Inventaris</h1>
        <div style={{ marginBottom: '20px', textAlign: 'center' }}>
          <label style={{ fontSize: '1.2em', marginRight: '10px' }}>Peran Pengguna:</label>
          <select 
            value={role} 
            onChange={e => setRole(e.target.value)} 
            style={{ 
              padding: '10px', 
              borderRadius: '5px', 
              border: 'none', 
              fontSize: '1em', 
              background: '#fff', 
              color: '#333' 
            }}
          >
            <option value="Admin">Admin</option>
            <option value="Karyawan">Karyawan</option>
          </select>
        </div>
        {lowStockItems.length > 0 && (
          <div style={{ 
            backgroundColor: '#ff6b6b', 
            color: 'white', 
            padding: '15px', 
            margin: '20px 0', 
            borderRadius: '10px', 
            boxShadow: '0 4px 8px rgba(0,0,0,0.2)' 
          }}>
            <h3 style={{ margin: '0 0 10px 0' }}>Peringatan Stok Hampir Habis:</h3>
            {lowStockItems.map(item => <p key={item.id} style={{ margin: '5px 0' }}>{item.name} - Stok: {item.stock}</p>)}
          </div>
        )}
        <div style={{ 
          background: 'rgba(255, 255, 255, 0.2)', 
          padding: '20px', 
          borderRadius: '10px', 
          marginBottom: '20px', 
          boxShadow: '0 4px 8px rgba(0,0,0,0.1)' 
        }}>
          <h2 style={{ marginTop: '0', color: '#fff' }}>Transaksi Barang</h2>
          <select 
            value={selectedItem} 
            onChange={e => setSelectedItem(e.target.value)} 
            style={{ 
              padding: '10px', 
              marginRight: '10px', 
              borderRadius: '5px', 
              border: 'none', 
              fontSize: '1em', 
              background: '#fff', 
              color: '#333' 
            }}
          >
            <option value="">Pilih Barang</option>
            {items.map(item => <option key={item.id} value={item.name}>{item.name}</option>)}
          </select>
          <button 
            onClick={scanBarcode} 
            style={{ 
              padding: '10px 15px', 
              background: '#4CAF50', 
              color: 'white', 
              border: 'none', 
              borderRadius: '5px', 
              cursor: 'pointer', 
              marginRight: '10px' 
            }}
          >
            Scan Barcode (Simulasi)
          </button>
          <br />
          <label style={{ marginRight: '10px', fontSize: '1.1em' }}>Jenis:</label>
          <select 
            value={type} 
            onChange={e => setType(e.target.value)} 
            style={{ 
              padding: '10px', 
              marginRight: '10px', 
              borderRadius: '5px', 
              border: 'none', 
              fontSize: '1em', 
              background: '#fff', 
              color: '#333' 
            }}
          >
            <option value="Masuk">Barang Masuk</option>
            <option value="Keluar">Barang Keluar</option>
          </select>
          <input 
            type="number" 
            placeholder="Jumlah" 
            value={quantity} 
            onChange={e => setQuantity(e.target.value)} 
            style={{ 
              padding: '10px', 
              marginRight: '10px', 
              borderRadius: '5px', 
              border: 'none', 
              fontSize: '1em', 
              background: '#fff', 
              color: '#333' 
            }} 
          />
          <button 
            onClick={handleTransaction} 
            style={{ 
              padding: '10px 15px', 
              background: '#2196F3', 
              color: 'white', 
              border: 'none', 
              borderRadius: '5px', 
              cursor: 'pointer' 
            }}
          >
            Simpan
          </button>
        </div>
        <div style={{ 
          background: 'rgba(255, 255, 255, 0.2)', 
          padding: '20px', 
          borderRadius: '10px', 
          marginBottom: '20px', 
          boxShadow: '0 4px 8px rgba(0,0,0,0.1)', 
          textAlign: 'center' 
        }}>
          <h3 style={{ margin: '0 0 10px 0', color: '#fff' }}>Stok Hadiah</h3>
          <ul style={{ listStyle: 'none', padding: 0, color: '#fff' }}>
            {rewardsItems.map(reward => (
              <li key={reward.name} style={{ margin: '5px 0' }}>
                {reward.name}: {reward.stock} tersedia
              </li>
            ))}
          </ul>
          <select 
            value={selectedReward} 
            onChange={e => setSelectedReward(e.target.value)} 
            style={{ 
              padding: '10px', 
              marginRight: '10px', 
              borderRadius: '5px', 
              border: 'none', 
              fontSize: '1em', 
              background: '#fff', 
              color: '#333' 
            }}
          >
            <option value="">Pilih Hadiah</option>
            {rewardsItems.filter(r => r.stock > 0).map(reward => (
              <option key={reward.name} value={reward.name}>{reward.name}</option>
            ))}
          </select>
          <button 
            onClick={redeemReward} 
            style={{ 
              padding: '10px 15px', 
              background: '#FF9800', 
              color: 'white', 
              border: 'none', 
              borderRadius: '5px', 
              cursor: 'pointer' 
            }}
          >
            Pilih Hadiah
          </button>
        </div>
        <div style={{ 
          background: 'rgba(255, 255, 255, 0.2)', 
          padding: '20px', 
          borderRadius: '10px', 
          marginBottom: '20px', 
          boxShadow: '0 4px 8px rgba(0,0,0,0.1)' 
        }}>
          <h2 style={{ marginTop: '0', color: '#fff' }}>Stok Tersisa</h2>
          <table style={{ width: '100%', borderCollapse: 'collapse', background: '#fff', color: '#333', borderRadius: '5px', overflow: 'hidden' }}>
            <thead>
              <tr style={{ background: '#f5f5f5' }}>
                <th style={{ padding: '10px', border: '1px solid #ddd' }}>Barang</th>
                <th style={{ padding: '10px', border: '1px solid #ddd' }}>Stok Tersisa</th>
                <th style={{ padding: '10px', border: '1px solid #ddd' }}>Batas Minimum</th>
                <th style={{ padding: '10px', border: '1px solid #ddd' }}>Status</th>
              </tr>
            </thead>
            <tbody>
              {items.map((item, index) => (
                <tr key={item.id} style={{ background: index % 2 === 0 ? '#f9f9f9' : '#fff' }}>
                  <td style={{ padding: '10px', border: '1px solid #ddd' }}>{item.name}</td>
                  <td style={{ padding: '10px', border: '1px solid #ddd' }}>{item.stock}</td>
                  <td style={{ padding: '10px', border: '1px solid #ddd' }}>{item.minStock}</td>
                  <td style={{ padding: '10px', border: '1px solid #ddd', color: item.stock <= item.minStock ? 'red' : 'green' }}>
                    {item.stock <= item.minStock ? 'Hampir Habis' : 'Normal'}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
        {role === 'Admin' && (
          <div style={{ 
            background: 'rgba(255, 255, 255, 0.2)', 
            padding: '20px', 
            borderRadius: '10px', 
            marginBottom: '20px', 
            boxShadow: '0 4px 8px rgba(0,0,0,0.1)' 
          }}>
            <h2 style={{ marginTop: '0', color: '#fff' }}>Dashboard Grafik</h2>
            <BarChart width={600} height={300} data={items}>
              <CartesianGrid strokeDasharray="3 3" />
              <XAxis dataKey="name" />
              <YAxis />
              <Tooltip />
              <Legend />
              <Bar dataKey="stock" fill="#8884d8" />
            </BarChart>
          </div>
        )}
        <div style={{ 
          background: 'rgba(255, 255, 255, 0.2)', 
          padding: '20px', 
          borderRadius: '10px', 
          marginBottom: '20px', 
          boxShadow: '0 4px 8px rgba(0,0,0,0.1)' 
        }}>
          <h2 style={{ marginTop: '0', color: '#fff' }}>Riwayat Transaksi</h2>
          <table style={{ width: '100%', borderCollapse: 'collapse', background: '#fff', color: '#333', borderRadius: '5px', overflow: 'hidden' }}>
            <thead>
              <tr style={{ background: '#f5f5f5' }}>
                <th style={{ padding: '10px', border: '1px solid #ddd' }}>Barang</th>
                <th style={{ padding: '10px', border: '1px solid #ddd' }}>Jenis</th>
                <th style={{ padding: '10px', border: '1px solid #ddd' }}>Jumlah</th>
                <th style={{ padding: '10px', border: '1px solid #ddd' }}>Tanggal</th>
              </tr>
            </thead>
            <tbody>
              {history.map((h, index) => (
                <tr key={index} style={{ background: index % 2 === 0 ? '#f9f9f9' : '#fff' }}>
                  <td style={{ padding: '10px', border: '1px solid #ddd' }}>{h.item}</td>
                  <td style={{ padding: '10px', border: '1px solid #ddd' }}>{h.type}</td>
                  <td style={{ padding: '10px', border: '1px solid #ddd' }}>{h.quantity}</td>
                  <td style={{ padding: '10px', border: '1px solid #ddd' }}>{h.date}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
        <div style={{ 
          background: 'rgba(255, 255, 255, 0.2)', 
          padding: '20px', 
          borderRadius: '10px', 
          boxShadow: '0 4px 8px rgba(0,0,0,0.1)' 
        }}>
          <h2 style={{ marginTop: '0', color: '#fff' }}>Riwayat Hadiah</h2>
          <table style={{ width: '100%', borderCollapse: 'collapse', background: '#fff', color: '#333', borderRadius: '5px', overflow: 'hidden' }}>
            <thead>
              <tr style={{ background: '#f5f5f5' }}>
                <th style={{ padding: '10px', border: '1px solid #ddd' }}>Jenis</th>
                <th style={{ padding: '10px', border: '1px solid #ddd' }}>Hadiah</th>
                <th style={{ padding: '10px', border: '1px solid #ddd' }}>Jumlah Hadiah</th>
                <th style={{ padding: '10px', border: '1px solid #ddd' }}>Tanggal</th>
              </tr>
            </thead>
            <tbody>
              {historyRewards.map((h, index) => (
                <tr key={index} style={{ background: index % 2 === 0 ? '#f9f9f9' : '#fff' }}>
                  <td style={{ padding: '10px', border: '1px solid #ddd' }}>Hadiah {h.type}</td>
                  <td style={{ padding: '10px', border: '1px solid #ddd' }}>{h.name || '-'}</td>
                  <td style={{ padding: '10px', border: '1px solid #ddd' }}>{h.quantity}</td>
                  <td style={{ padding: '10px', border: '1px solid #ddd' }}>{h.date}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}

export default App;
